import math

class Solution(object):
    def minNumberOfSeconds(self, mountainHeight, workerTimes):
        def max_reduce(w, T):
            return int((-1 + math.sqrt(1 + 8.0 * T / w)) / 2)

        def feasible(T):
            return sum(max_reduce(w, T) for w in workerTimes) >= mountainHeight

        max_w = max(workerTimes)
        hi = max_w * mountainHeight * (mountainHeight + 1) // 2
        lo = 0
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo
